let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const languages = input.languages || ['hu'];
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const aiModel = input.aiModel || 'deepseek-v4-flash';
const customPrompt = input.customPrompt || '';
const apiKeyOverride = input.apiKeyOverride || '';
const notifyEmail = input.notifyEmail || '';
const logoMode = input.logoMode || 'upload';
const logoPrompt = input.logoPrompt || '';
const colors = input.colors || { primary: '#6366f1', secondary: '#8b5cf6', accent: '#f59e0b', headerBg: '#ffffff' };
const headerLogo = input.headerLogo || null;
const footerLogo = input.footerLogo || null;
const header = input.header || [];
const footer = input.footer || [];
const hero = input.hero || { enabled: true, height: 600 };

let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}
if (pages.length === 0) {
  pages = [{ name: 'Kezdőlap', slug: 'home', description: '', subpages: [] }, { name: 'Rólunk', slug: 'about', description: '', subpages: [] }, { name: 'Kapcsolat', slug: 'contact', description: '', subpages: [] }];
}

return { businessName, projectType, languages, description, designStyle, aiModel, customPrompt, apiKeyOverride, notifyEmail, logoMode, logoPrompt, colors, headerLogo, footerLogo, header, hero, footer, pages };

const https = require('https');

const data = $input.all()[0].json;
const lang = data.languages[0] || 'hu';

const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  if (p.subpages && p.subpages.length > 0) line += ' [Aloldalak: ' + p.subpages.map(sp => sp.name + '(' + sp.slug + ')' + (sp.description ? ': ' + sp.description : '')).join(', ') + ']';
  return line;
}).join('\n');

const heroInfo = data.hero && data.hero.enabled ? `Hero: YES, height: ${data.hero.height}px.` : 'Hero: NO.';
const headerInfo = data.header && data.header.length > 0 ? 'Header: ' + data.header.join(', ') : 'Header: standard';
const footerInfo = data.footer && data.footer.length > 0 ? 'Footer: ' + data.footer.join(', ') : 'Footer: standard';
const anyAi = [data.colors.primary,data.colors.secondary,data.colors.accent,data.colors.headerBg].filter(c => c === 'ai').length > 0;

const logoInstruction = data.logoMode === 'ai' && data.logoPrompt
  ? `\n\nALSO GENERATE an SVG logo: ${data.logoPrompt}. Include the SVG code in the response under a "logo" key with a "svg" field containing the raw SVG markup.`
  : '';

// Egyszerűbb, biztonságosabb prompt – kevesebb JSON formátumú utasítás
const base = `You are a Gravity CMS expert. Create a website for:

Business: ${data.businessName}
Type: ${data.projectType}
Language: ${lang}
Description: ${data.description}
Design style: ${data.designStyle}
Colors: primary=${data.colors.primary}, secondary=${data.colors.secondary}, accent=${data.colors.accent}
${heroInfo}
${headerInfo}
${footerInfo}

Pages to generate:
${pageList}
${logoInstruction}

Respond with a JSON object containing:
1. "pages" - an object where keys are page slugs, each containing title, content (with hero, sections), meta
2. "config" - system settings, theme colors, header/footer config, plugin list
3. "admin_structure" - admin blueprints

IMPORTANT: Return ONLY the JSON object. No markdown, no code fences, just the raw JSON.`;

const prompt = data.customPrompt ? base + '\n\nADDITIONAL: ' + data.customPrompt : base;
const apiKey = data.apiKeyOverride || $env.DEEPSEEK_API_KEY || '';

if (!apiKey) throw new Error('Missing API key');

const requestBody = JSON.stringify({
  model: data.aiModel,
  messages: [
    { role: 'system', content: 'You are an expert Gravity CMS developer. Always respond with pure JSON (no markdown, no code fences).' },
    { role: 'user', content: prompt }
  ],
  temperature: 0.7,
  max_tokens: 4096,
  response_format: { type: 'json_object' }
});

const result = await new Promise((resolve, reject) => {
  const options = {
    hostname: 'api.deepseek.com',
    port: 443,
    path: '/v1/chat/completions',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + apiKey,
      'Content-Length': Buffer.byteLength(requestBody)
    },
    timeout: 120000
  };
  const req = https.request(options, (res) => {
    let body = '';
    res.on('data', chunk => body += chunk);
    res.on('end', () => {
      try { const json = JSON.parse(body); if (json.error) reject(new Error(json.error.message || JSON.stringify(json.error))); else resolve(json); }
      catch (e) { reject(new Error('JSON parse error: ' + body.substring(0, 300))); }
    });
  });
  req.on('error', reject);
  req.on('timeout', () => { req.destroy(); reject(new Error('Timeout')); });
  req.write(requestBody);
  req.end();
});

return { ...result, _businessName: data.businessName };

const fs = require('fs');
const path = require('path');

const response = $input.all()[0].json;

// AI válasz feldolgozása
let content;
let rawText = '';
if (response.choices) {
  rawText = response.choices[0].message.content;
  try {
    let jsonStr = rawText;
    // Tisztítsuk a választ
    if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
    else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
    else if (jsonStr.startsWith('{')) jsonStr = jsonStr;
    else jsonStr = jsonStr.substring(jsonStr.indexOf('{'), jsonStr.lastIndexOf('}') + 1);
    content = JSON.parse(jsonStr);
  } catch (e) {
    content = { error: "Parse failed", raw: rawText.substring(0, 1000) };
  }
} else {
  content = { error: "No choices in response", apiResponse: response };
  rawText = JSON.stringify(response);
}

const bizName = response._businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = new Date().toISOString().replace(/[:.]/g, '-');

// ---- JSON mentés ----
const outputDir = '/home/node/output';
const jsonFile = path.join(outputDir, safeName + '_' + ts + '.json');
try { if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true }); fs.writeFileSync(jsonFile, JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// ---- Verziókövetés ----
const versionsDir = path.join(outputDir, 'versions');
try { if (!fs.existsSync(versionsDir)) fs.mkdirSync(versionsDir, { recursive: true }); fs.writeFileSync(path.join(versionsDir, safeName + '_' + ts + '.json'), JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// ---- GRAVITY CMS DEPLOY (.md fájlok) ----
const gravPagesDir = '/home/node/gravity-pages';
try {
  const pageDir = path.join(gravPagesDir, '01.' + safeName);
  if (!fs.existsSync(pageDir)) fs.mkdirSync(pageDir, { recursive: true });

  if (content.pages) {
    // SIKERES: oldalak a JSON-ból
    Object.keys(content.pages).forEach(slug => {
      const page = content.pages[slug];
      const mdName = slug === 'home' ? 'default.md' : slug + '.md';
      let md = '---\ntitle: "' + (page.title || slug) + '"\n';
      if (page.meta) md += 'metadata:\n  description: "' + (page.meta.description || '') + '"\n';
      md += 'visible: true\n---\n\n';
      if (page.content && page.content.hero) {
        md += '# ' + (page.content.hero.title || '') + '\n\n';
        if (page.content.hero.subtitle) md += page.content.hero.subtitle + '\n\n';
      }
      if (page.content && page.content.sections) {
        page.content.sections.forEach(sec => {
          md += '## ' + (sec.title || '') + '\n\n' + (sec.content || '') + '\n\n';
        });
      }
      fs.writeFileSync(path.join(pageDir, mdName), md, 'utf8');
    });
  } else {
    // PARSE FAILED: nyers szöveg mentése .md fájlba
    let rawMd = '---\ntitle: "' + bizName + '"\nvisible: true\n---\n\n';
    rawMd += '# ' + bizName + '\n\n';
    rawMd += '> ⚠️ Az AI válasz JSON parse-olása sikertelen volt. Itt a nyers válasz:\n\n';
    rawMd += rawText;
    fs.writeFileSync(path.join(pageDir, 'default.md'), rawMd, 'utf8');
  }
} catch (err) {
  console.error('Gravity deploy error:', err.message);
}

return {
  generated: content,
  saved_to: jsonFile,
  gravity_deployed: true,
  gravity_path: '01.' + safeName,
  timestamp: new Date().toISOString(),
  model: response.model || 'deepseek-v4-flash',
  usage: response.usage || {}
};
